INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'freelance_service',
  'us_new_york',
  2,
  'Freelance Services Agreement (New York)',
  'This Freelance Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}} ("Hiring Party"), with address at {{party_a_address}}, and {{party_b_name}} doing business as {{party_b_company}} ("Freelance Worker"), with address at {{party_b_address}}.',
  'WHEREAS, Hiring Party wishes to engage Freelance Worker to provide certain freelance services as described herein;
WHEREAS, Freelance Worker wishes to provide such services on the terms set out in this Agreement;
WHEREAS, the parties intend this Agreement to comply with all applicable New York law, including the New York City Freelance Isn''t Free Act (NYC Administrative Code § 20-927 et seq., also known as Local Law 140 of 2016) and the New York State Freelance Isn''t Free Act (NY Labor Law Article 44, effective May 20, 2024), as applicable;
WHEREAS, this Agreement constitutes a written contract as required by law for freelance work valued at $800 or more;
NOW, THEREFORE, in consideration of the mutual covenants herein, the parties agree as follows:',
  '[{"id":"fifa_rights_disclosure","title":"1. FREELANCE ISN''T FREE ACT DISCLOSURE","content":"1.1 Purpose. This Section provides Freelance Worker with notice of their rights under the New York City Freelance Isn''t Free Act (NYC Administrative Code § 20-927 et seq., \"Local Law 140\") and/or the New York State Freelance Isn''t Free Act (NY Labor Law Article 44), as applicable (collectively, \"FIFA\").\n\n1.2 Written Contract Requirement. For freelance work valued at $800 or more (whether paid as a single payment or as multiple payments for contracts entered into within 120 days of one another), FIFA requires the Hiring Party to provide a written contract. This Agreement satisfies that requirement.\n\n1.3 Freelance Worker Rights. Under FIFA, Freelance Worker has the right to:\n(a) A written contract for work valued at $800 or more;\n(b) Timely payment within 30 days of completion (or per the agreed schedule);\n(c) Freedom from retaliation for exercising these rights;\n(d) File a complaint with the NYC Department of Consumer and Worker Protection (DCWP) or NY Department of Labor for violations.\n\n1.4 Hiring Party Acknowledgment. By signing this Agreement, Hiring Party acknowledges they have read, understand, and agree to comply with all applicable FIFA requirements.\n\n1.5 Posting of Notice. Hiring Party shall post or provide notice of freelance worker rights as required by applicable law.","type":"required","order":1},{"id":"scope_of_work","title":"2. SCOPE OF WORK (FIFA REQUIRED TERMS)","content":"2.1 Services Description. Freelance Worker shall provide the following services (the \"Services\"): {{services_description}}.\n\n2.2 Deliverables. Freelance Worker shall deliver the following work products: {{deliverables_description}}.\n\n2.3 Project Timeline. The Services shall be performed according to the following schedule:\n(a) Start Date: {{effective_date}}\n(b) Estimated Completion Date: {{expiration_date}}\n(c) Milestones (if applicable): {{milestones_description}}\n\n2.4 Value of Services. The total value of the Services under this Agreement is estimated at: {{payment_amount}}.\n\n2.5 Changes to Scope. Any changes to the Services, deliverables, timeline, or compensation must be agreed upon in writing by both parties before work on the changed scope begins.\n\n2.6 FIFA Compliance. This scope of work section is provided in compliance with FIFA requirements that a written contract include: (i) the name and contact information of both parties; (ii) an itemization of services to be provided; (iii) the value of the services; (iv) the rate and method of compensation; and (v) the date by which payment is due or the mechanism for determining such date.","type":"required","order":2},{"id":"payment","title":"3. PAYMENT TERMS (30-DAY FIFA REQUIREMENT)","content":"3.1 Compensation. Hiring Party shall pay Freelance Worker as follows:\n(a) Project Fee: {{payment_amount}}; OR\n(b) Hourly Rate: {{hourly_rate}} per hour for time worked on the Services.\n\n3.2 Payment Due Date - FIFA 30-Day Requirement. Except as otherwise expressly provided in this Agreement:\n(a) Hiring Party shall pay Freelance Worker within thirty (30) days after the completion of the Services;\n(b) If payment is contingent on completion of milestones, payment for each milestone shall be due within thirty (30) days after completion of that milestone;\n(c) For ongoing services, payment shall be made according to the schedule specified in Section 3.4.\n\n3.3 Payment Schedule (If Applicable). If the parties agree to a payment schedule other than upon completion, payments shall be made as follows: {{payment_schedule}}.\n\n3.4 Invoicing. Freelance Worker shall submit invoices:\n(a) Upon completion of the Services or applicable milestone; OR\n(b) In accordance with the schedule specified in {{services_description}}.\nHiring Party shall pay each proper invoice within thirty (30) days of receipt.\n\n3.5 Method of Payment. Payment shall be made by: {{payment_method}}.\n\n3.6 Expenses. Freelance Worker is responsible for all expenses incurred in performing the Services, unless otherwise agreed in writing and pre-approved by Hiring Party.\n\n3.7 Taxes. Freelance Worker is solely responsible for all federal, state, and local taxes on compensation received, including New York State and City income taxes. Hiring Party will not withhold payroll taxes from payments to Freelance Worker.","type":"required","order":3},{"id":"late_payment_fifa_penalties","title":"4. LATE PAYMENT AND FIFA PENALTIES","content":"4.1 Timely Payment Obligation. Hiring Party understands that timely payment is required by law and that failure to pay on time may result in significant legal consequences.\n\n4.2 FIFA Penalty Disclosure. Under FIFA, if Hiring Party fails to pay Freelance Worker in a timely manner, Freelance Worker may be entitled to:\n(a) Double Damages: An award of double the amount of underpayment;\n(b) Injunctive Relief: A court order requiring payment and/or prohibiting certain conduct;\n(c) Attorneys'' Fees: Recovery of reasonable attorneys'' fees and costs;\n(d) Statutory Damages: For violations of the written contract requirement, damages equal to $250 or the value of the contract (whichever is less);\n(e) Civil Penalties: The City or State may impose civil penalties on the Hiring Party.\n\n4.3 Interest on Late Payments. In addition to statutory remedies, late payments shall accrue interest at the rate of one percent (1%) per month, or the maximum rate permitted by law, whichever is less.\n\n4.4 Dispute Resolution Before Legal Action. Before pursuing legal remedies, Freelance Worker agrees to provide written notice to Hiring Party of any payment dispute and allow seven (7) days for Hiring Party to cure the default. This provision does not limit or waive any statutory rights.","type":"required","order":4},{"id":"anti_retaliation","title":"5. ANTI-RETALIATION PROTECTIONS","content":"5.1 Prohibited Conduct. Hiring Party shall not retaliate against Freelance Worker for exercising any right under this Agreement or under applicable law. Prohibited retaliatory conduct includes, but is not limited to:\n(a) Threatening, intimidating, or harassing Freelance Worker;\n(b) Disciplining or terminating the engagement in bad faith;\n(c) Blacklisting or refusing to work with Freelance Worker in the future;\n(d) Denying referrals or opportunities;\n(e) Reporting or threatening to report Freelance Worker to immigration authorities;\n(f) Taking any other adverse action because Freelance Worker exercised their rights.\n\n5.2 Protected Activities. It shall not be considered a breach of this Agreement for Freelance Worker to:\n(a) File a complaint with any government agency regarding violations of this Agreement or applicable law;\n(b) Communicate with other freelance workers about terms and conditions of work;\n(c) Participate in any investigation or proceeding relating to freelance worker rights;\n(d) Seek legal advice or representation regarding their rights.\n\n5.3 FIFA Retaliation Remedies. Under FIFA, if Hiring Party retaliates against Freelance Worker, Freelance Worker may be entitled to statutory damages, injunctive relief, attorneys'' fees, and other remedies provided by law.\n\n5.4 Survival. This Section 5 shall survive termination of this Agreement.","type":"required","order":5},{"id":"dispute_resolution_dcwp","title":"6. DISPUTE RESOLUTION AND DCWP COMPLAINT PROCESS","content":"6.1 Good Faith Negotiation. The parties shall attempt to resolve any dispute arising out of this Agreement through good faith informal negotiation for a period of fourteen (14) days before pursuing other remedies.\n\n6.2 Right to File Complaint. Freelance Worker has the right to file a complaint with:\n(a) NYC Department of Consumer and Worker Protection (DCWP): For violations of the NYC Freelance Isn''t Free Act (Local Law 140). Complaints may be filed online at nyc.gov/dcwp or by calling 311.\n(b) NY Department of Labor: For violations of the NY State Freelance Isn''t Free Act (Labor Law Article 44). Complaints may be filed at dol.ny.gov.\n(c) Civil Court: Freelance Worker may also bring a civil action in any court of competent jurisdiction.\n\n6.3 DCWP Services. The NYC DCWP may:\n(a) Investigate complaints of non-payment or late payment;\n(b) Attempt to resolve disputes through mediation;\n(c) Take enforcement action against Hiring Parties who violate the law;\n(d) Provide navigation services to help freelance workers understand their rights.\n\n6.4 Statute of Limitations. Freelance Worker should be aware that claims under FIFA generally must be brought within six (6) years of the date the payment was due.\n\n6.5 No Waiver of Rights. Nothing in this Agreement shall be construed to waive Freelance Worker''s right to file a complaint with any government agency or to pursue legal remedies. Any such waiver is void as against public policy.","type":"required","order":6},{"id":"freelancer_status","title":"7. FREELANCE WORKER STATUS","content":"7.1 Independent Contractor. Freelance Worker is an independent contractor, not an employee, partner, joint venturer, or agent of Hiring Party.\n\n7.2 Control. Freelance Worker shall determine the manner, method, and means of performing the Services, subject to meeting agreed deliverables and deadlines. Hiring Party shall not direct or control the details of how the work is performed.\n\n7.3 Equipment and Materials. Freelance Worker shall provide their own equipment, tools, software, and materials necessary to perform the Services.\n\n7.4 No Exclusivity. Freelance Worker may work for other clients concurrently, provided such work does not create a conflict of interest or interfere with obligations under this Agreement.\n\n7.5 No Benefits. Freelance Worker is not entitled to employee benefits, including but not limited to health insurance, retirement benefits, paid time off, or workers'' compensation.\n\n7.6 New York Classification. The parties intend that Freelance Worker be properly classified as an independent contractor under all applicable New York law, including the ABC test and other applicable classification standards.","type":"standard","order":7},{"id":"term","title":"8. TERM AND TERMINATION","content":"8.1 Term. This Agreement is effective from the Effective Date and continues until {{expiration_date}}, or until the Services are completed and final payment is made, whichever occurs later, unless terminated earlier.\n\n8.2 Termination for Convenience. Either party may terminate this Agreement by giving {{notice_period}} days'' written notice to the other party.\n\n8.3 Termination for Cause. Either party may terminate this Agreement immediately upon written notice if the other party:\n(a) Materially breaches this Agreement and fails to cure within seven (7) days of written notice;\n(b) Becomes insolvent or files for bankruptcy;\n(c) Commits fraud or willful misconduct.\n\n8.4 Effect of Termination. Upon termination:\n(a) Freelance Worker shall cease work and deliver all completed work product;\n(b) Hiring Party shall pay for all Services performed through the termination date within thirty (30) days, as required by FIFA;\n(c) Each party shall return or destroy Confidential Information of the other party.\n\n8.5 Survival. Sections relating to payment, confidentiality, intellectual property, liability, and dispute resolution shall survive termination.","type":"standard","order":8},{"id":"intellectual_property","title":"9. INTELLECTUAL PROPERTY","content":"9.1 Work Product. \"Work Product\" means all materials, deliverables, inventions, works of authorship, and other intellectual property created by Freelance Worker in performing the Services.\n\n9.2 Assignment Upon Payment. Upon receipt of full payment, Freelance Worker hereby assigns to Hiring Party all right, title, and interest in and to the Work Product, including all intellectual property rights therein.\n\n9.3 Condition Precedent. The assignment in Section 9.2 is expressly conditioned upon Freelance Worker receiving full payment. Until full payment is received, Freelance Worker retains all rights in the Work Product.\n\n9.4 Background IP. Freelance Worker retains all rights in pre-existing intellectual property (\"Background IP\"). If any Background IP is incorporated into the Work Product, Freelance Worker grants Hiring Party a perpetual, non-exclusive, royalty-free, worldwide license to use such Background IP solely as part of the Work Product.\n\n9.5 Moral Rights. To the extent permitted by law, Freelance Worker waives any moral rights in the Work Product.\n\n9.6 Portfolio Rights. Unless otherwise agreed in writing, Freelance Worker may display completed Work Product in their portfolio for self-promotion purposes, subject to confidentiality obligations.","type":"negotiable","order":9},{"id":"confidentiality","title":"10. CONFIDENTIALITY","content":"10.1 Confidential Information. \"Confidential Information\" means non-public information disclosed by one party to the other that is designated as confidential or that reasonably should be understood to be confidential.\n\n10.2 Obligations. Each party shall: (a) use Confidential Information only for purposes of this Agreement; (b) protect Confidential Information with at least reasonable care; (c) not disclose Confidential Information except to those with a need to know who are bound by confidentiality obligations.\n\n10.3 Exclusions. Confidential Information does not include information that: (a) is or becomes publicly available without breach; (b) was known to the receiving party before disclosure; (c) is received from a third party without restriction; (d) is independently developed.\n\n10.4 Required Disclosure. A party may disclose Confidential Information if required by law, provided that party gives prompt notice (where legally permitted) and cooperates in seeking protective treatment.\n\n10.5 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held criminally or civilly liable for disclosure of a trade secret made in confidence to a government official or attorney for the purpose of reporting a suspected violation of law.\n\n10.6 Duration. Confidentiality obligations survive termination for {{confidentiality_period}} years.","type":"standard","order":10},{"id":"warranties","title":"11. WARRANTIES","content":"11.1 Freelance Worker Warranties. Freelance Worker represents and warrants that:\n(a) They have full authority to enter this Agreement;\n(b) The Services will be performed in a professional and workmanlike manner;\n(c) The Work Product will be original and will not infringe any third-party intellectual property rights;\n(d) They have the right to assign the intellectual property in the Work Product upon payment;\n(e) They will comply with all applicable laws in performing the Services.\n\n11.2 Hiring Party Warranties. Hiring Party represents and warrants that:\n(a) They have full authority to enter this Agreement;\n(b) Materials provided to Freelance Worker will not infringe any third-party rights;\n(c) They will comply with all applicable laws, including FIFA.\n\n11.3 Disclaimer. Except as expressly stated, neither party makes additional warranties, express or implied.","type":"standard","order":11},{"id":"liability","title":"12. LIMITATION OF LIABILITY","content":"12.1 Exclusion of Consequential Damages. Except for breaches of confidentiality, intellectual property infringement, or fraud, neither party shall be liable for indirect, incidental, special, or consequential damages.\n\n12.2 Cap on Liability. Except for breaches of confidentiality, intellectual property infringement, or fraud, each party''s total liability shall not exceed the total fees paid or payable under this Agreement.\n\n12.3 Exceptions. Nothing in this Section limits liability for: (a) fraud or intentional misconduct; (b) death or personal injury caused by negligence; (c) matters that cannot be limited by law.\n\n12.4 FIFA Rights Preserved. NOTWITHSTANDING ANY OTHER PROVISION OF THIS AGREEMENT, NOTHING IN THIS SECTION OR ELSEWHERE IN THIS AGREEMENT SHALL LIMIT, WAIVE, OR MODIFY FREELANCE WORKER''S RIGHTS OR HIRING PARTY''S OBLIGATIONS UNDER THE FREELANCE ISN''T FREE ACT, INCLUDING THE RIGHT TO RECOVER DOUBLE DAMAGES, ATTORNEYS'' FEES, INJUNCTIVE RELIEF, AND OTHER STATUTORY REMEDIES.\n\n12.5 Insurance. Freelance Worker is advised to maintain appropriate professional liability insurance coverage.","type":"negotiable","order":12},{"id":"general","title":"13. GENERAL PROVISIONS","content":"13.1 Governing Law. This Agreement is governed by the laws of the State of New York, without regard to conflict of laws principles.\n\n13.2 Venue. The parties consent to exclusive jurisdiction of the state and federal courts located in {{venue_county}} County, New York.\n\n13.3 Notices. All notices shall be in writing and delivered by hand, certified mail, or email to the addresses set forth above.\n\n13.4 Assignment. Neither party may assign this Agreement without the other''s written consent, except to a successor entity in connection with a merger or sale of substantially all assets.\n\n13.5 Entire Agreement. This Agreement, including any attached exhibits, constitutes the entire agreement and supersedes all prior negotiations and agreements.\n\n13.6 Amendments. Amendments must be in writing and signed by both parties.\n\n13.7 Severability. If any provision is found invalid, the remaining provisions shall continue in effect, and the invalid provision shall be modified to the minimum extent necessary to make it valid.\n\n13.8 Waiver. Failure to enforce any provision is not a waiver of the right to enforce it later. Waivers must be in writing.\n\n13.9 Force Majeure. Neither party is liable for delays due to circumstances beyond their reasonable control, provided that payment obligations are not excused.\n\n13.10 Counterparts. This Agreement may be signed in counterparts, including electronically, each of which is an original. Electronic signatures are valid under New York ESRA and the federal ESIGN Act.\n\n13.11 Record Retention. Hiring Party shall retain a copy of this Agreement for at least six (6) years after the termination date, as required by applicable law.\n\n13.12 Headings. Section headings are for convenience only and do not affect interpretation.","type":"standard","order":13}]'::jsonb,
  'IN WITNESS WHEREOF, the parties have executed this Freelance Services Agreement as of {{signature_date}}.

IMPORTANT NOTICE TO FREELANCE WORKER: By signing below, you acknowledge that you have been informed of your rights under the New York Freelance Isn''t Free Act, including your right to timely payment, freedom from retaliation, and the ability to file a complaint with the NYC Department of Consumer and Worker Protection or NY Department of Labor.

HIRING PARTY:
{{party_a_company}}

By: ______________________________
Printed Name: {{party_a_name}}
Title: {{party_a_title}}
Email: {{party_a_email}}
Date: {{signature_date}}

FREELANCE WORKER:
{{party_b_company}}

By: ______________________________
Printed Name: {{party_b_name}}
Email: {{party_b_email}}
Date: {{signature_date}}

HIRING PARTY ACKNOWLEDGMENT: I, the undersigned, acknowledge that I have read and understand my obligations under the New York Freelance Isn''t Free Act, including the requirement to pay within 30 days of completion and the prohibition on retaliation.

Hiring Party Initials: ______',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Hiring party email address","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Hiring party full legal name","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Hiring party full address","category":"party_a","type":"textarea","required":true,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Hiring party company or business name","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title or role","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Freelancer Email","description":"Freelance worker email address","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Freelancer Name","description":"Freelance worker full legal name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Freelancer Address","description":"Freelance worker full address","category":"party_b","type":"textarea","required":true},{"id":"party_b_company","token":"{{party_b_company}}","label":"Business Name","description":"Freelance worker business or DBA name","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Start Date","description":"Agreement start date","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"End Date","description":"Agreement end date or estimated completion","category":"dates","type":"date","required":true},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"New York county for legal venue (e.g., New York, Kings, Queens)","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice required for termination","category":"terms","type":"number","required":false,"default":"14"},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Years confidentiality obligations continue","category":"terms","type":"number","required":false,"default":"3"},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour (if applicable)","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Project Fee / Total Value","description":"Total project fee or estimated value of services","category":"financial","type":"currency","required":true},{"id":"payment_schedule","token":"{{payment_schedule}}","label":"Payment Schedule","description":"Payment schedule if not lump sum (e.g., 50% upfront, 50% on completion)","category":"financial","type":"textarea","required":false},{"id":"payment_method","token":"{{payment_method}}","label":"Payment Method","description":"How payment will be made (e.g., bank transfer, check, PayPal)","category":"financial","type":"text","required":false,"default":"bank transfer or electronic payment"},{"id":"services_description","token":"{{services_description}}","label":"Services Description","description":"Detailed description of services to be provided","category":"project","type":"textarea","required":true},{"id":"deliverables_description","token":"{{deliverables_description}}","label":"Deliverables","description":"Specific work products or deliverables","category":"project","type":"textarea","required":true},{"id":"milestones_description","token":"{{milestones_description}}","label":"Milestones","description":"Project milestones and deadlines (if applicable)","category":"project","type":"textarea","required":false}]'::jsonb,
  true,
